class BookMyShow {
public:
    BookMyShow(int n, int m) : n(n), m(m), seats(n, vector<bool>(m, true)) {}

    vector<int> gather(int k, int maxRow) {
        for (int i = 0; i <= min(maxRow, n - 1); i++) {
            int cnt = 0;
            for (int j = 0; j < m; j++) {
                if (seats[i][j]) cnt++;
                else cnt = 0;
                if (cnt == k) return {i, j - k + 1};
            }
        }
        return {};
    }

    bool scatter(int k, int maxRow) {
        int cnt = 0;
        for (int i = 0; i <= min(maxRow, n - 1); i++) {
            for (int j = 0; j < m; j++) {
                if (seats[i][j]) cnt++;
                if (cnt == k) {
                    for (int l = j - k + 1; l <= j; l++) seats[i][l] = false;
                    return true;
                }
            }
        }
        return false;
    }

private:
    int n, m;
    vector<vector<bool>> seats;
};
```
